var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>그라운드 원</color>\\n제3 선착장 코핀 컴퍼니 임시 본사","JPN":"管理局直轄都市<color=#ffd34c>グラウンド・ワン</color>\\n第3船着き場コフィンカンパニー臨時本社","ENG":"Administration Direct Control City, <color=#ffd34c>Ground One</color>\\nDock No. 3, Coffin Company Temporary HQ","TWN":"管理局直轄城市<color=#ffd34c>G1</color>\\n第3碼頭科芬公司臨時總部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"음? 이 번호는 미나 씨잖아……?","JPN":"うん？　この番号はミナさん……？","ENG":"Hmm? This number... it's Mina's.","TWN":"嗯？這個號碼是米娜的……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE_2"},{"id":"L6_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"이런 시간에 어쩐 일이지?","JPN":"こんな時間にどうしたんだろう？","ENG":"What's she calling for at this hour?","TWN":"這麼晚了有什麼事嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어머, 미나 씨! 오랜만이네요!","JPN":"あら、ミナさん！　お久しぶりです！","ENG":"Oh! Mina! It's been a while!","TWN":"喔，米娜！好久不見了！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L10_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"오늘 퇴원한다고 들었는데, 이제 몸은 좀 괜찮으신가요?","JPN":"今日退院だと聞きましたけど、もう具合は大丈夫なんですか？","ENG":"I heard you were being discharged today. Feeling any better?","TWN":"聽說你今天出院，現在身體好些了嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"관리부장 님! 뭐 좀 물어볼 게 있어. 중요한 거야!","JPN":"管理部長！　ちょっと聞きたいことがある。大事なことなの！","ENG":"I have something to ask. It's important!","TWN":"管理部長！我有點事想問你，這事很重要！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네에? 중요하디니… 갑자기 무슨 일인가요?","JPN":"え？　大事なことって……急になんですか？","ENG":"Huh? Important...? What's going on all of a sudden?","TWN":"嗯？重要的事情……突然有什麼事嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"몇 달 전에 있었던 펜릴 소대 신입 사원 채용 공고 기억하지?","JPN":"数か月前にあった、フェンリル小隊の新入社員採用告知、覚えてる？","ENG":"Remember the Fenrir Squad recruitment posting from a few months back?","TWN":"還記得幾個月前芬里爾小隊新增員工的徵才公告嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그때, 지원자가 엄청 몰렸다가, 관리국 감사 때문에 다들 지원을 취소해 버렸잖아?","JPN":"あの時、最初は志願者が多かったけど、管理局の監査のせいでみんなキャンセルになったじゃない？","ENG":"There was a huge flood of applicants at first, but then everyone backed out after the Administration audit, right?","TWN":"那時候，申請者蜂擁而至，但因為管理局的審查，大家都取消了申請，不是嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아아, 네. 기억하죠.","JPN":"ああ、はい。覚えています。","ENG":"Ah, right. I remember.","TWN":"啊，是的，我記得。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그래서 결국 지원자는 한 명 밖에 남지 않았잖아요.","JPN":"それで、結局志願者は1人しか残りませんでしたよね。","ENG":"In the end, only one applicant remained.","TWN":"所以最後只剩下一個人來面試。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그, 그렇지……!?","JPN":"そ、そうだよね……！？","ENG":"R-right...?!","TWN":"是那、那樣嗎……？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼, 그때 면접 봤던 녀석, 혹시 관리부장 님은 누구인지 기억해?","JPN":"じゃあ、あの時面接を受けた人が誰だったか、管理部長は覚えてる？","ENG":"So, do you happen to remember who that last interviewee was?","TWN":"那麼，那時候面試的傢伙，還記得管理部長是誰嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네? 그야 당연히 기억하긴 하지만…….","JPN":"え？　それはもちろん、覚えていますけど……","ENG":"Huh? Well, of course I remember, but...","TWN":"什麼？那當然記得……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"누구였어!? 그 녀석의 이름을 말해 봐!!","JPN":"誰！？　そいつの名前言ってみて！！","ENG":"Then tell me! What was her name!?","TWN":"是誰？！說出那傢伙的名字！！！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"미나 씨, 갑자기 무슨 일 때문에 이러시는지 모르겠지만 일단 진정하세요.","JPN":"ミナさん、急にどうされたのかわかりませんが、とりあえず落ち着いてください。","ENG":"Mina, I don't know what's going on, but please calm down.","TWN":"米娜，不知道你突然這樣是為了什麼，但請先冷靜下來。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"미나 씨가 이렇게 흥분한 모습 처음 본다고요.","JPN":"こんなに取り乱しているミナさんは初めてです。","ENG":"I've never seen you so agitated before.","TWN":"我還是第一次看到米娜如此激動的樣子。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……아, 미안.","JPN":"……あ、ごめん。","ENG":"...Ah, sorry.","TWN":"……啊，抱歉。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"관리부장님한테는 갑작스러웠을지도 모르겠지만, 그래도 중요한 일이거든.","JPN":"突然すぎて困らせてしまったけど……でも大事なことなの。","ENG":"It might seem sudden to you, but this really is important.","TWN":"雖然對管理部長來說可能有些突然，但這確實是件重要的事。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"어쩌면 그 녀석, 좋지 못한 일에 휘말렸을지도 몰라서…….","JPN":"もしかしたらあいつ、何かよからぬことに巻き込まれてるのかもしれないし……","ENG":"She might have gotten caught up in something bad...","TWN":"或許那傢伙……可能捲入了不好的事情……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네에? 그럼, 나이엘 씨에게 무슨 일이라도 생긴 건가요?","JPN":"え？　ということは、ナイエルさんに何かあったんですか？","ENG":"Huh? Wait, did something happen to Naielle?","TWN":"是嗎？那奈爾發生什麼事了嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나이엘이라고……?","JPN":"ナイエル……？","ENG":"Did you say Naielle?","TWN":"奈爾……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네? 지금 나이엘 씨 이야기하는 거 아니었나요?","JPN":"えっ？　今ナイエルさんの話をしていたのではなかったですか？","ENG":"Wait a second... aren't we talking about Naielle?","TWN":"是？現在不是在說奈爾的事嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그 날, 마지막까지 남아있던 지원자는 나이엘 씨뿐이었잖아요.","JPN":"あの日、最後まで残っていた志願者はナイエルさんだけ……でしたよね？","ENG":"She was the only applicant who stuck it out until the end that day.","TWN":"那天，最後留下來面試的人只有奈爾。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"소대장님께서 부재중이라, 대신 미나 씨가 실전 면접을 진행하게 되었고…….","JPN":"小隊長が不在で、ミナさんが代わりに実戦面接を執り行って……","ENG":"Since the Commander was away, Mina, you were the one who conducted the field interview...","TWN":"由於小隊長不在，由米娜代為主持實戰面試……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그 결과는…….","JPN":"その結果は……","ENG":"And the result was...","TWN":"結果是……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……내가 나이엘한테 불합격을 줬다고?","JPN":"……私がナイエルを不合格にした？","ENG":"...You're telling me I failed her?","TWN":"……我給了奈爾不合格的評價？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네, 정말로 기억 안 나세요?","JPN":"はい。本当に覚えていないんですか？","ENG":"Yes, you really don't remember?","TWN":"是，你真的不記得了嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그날, 나이엘 씨가 이대로 포기할 수 없다면서 얼마나 떼를 썼는데요.","JPN":"あの日、このまま諦めるわけにはいかないって、ナイエルさんがすっごく意地を張って。","ENG":"That day, she insisted she couldn't give up like that.","TWN":"那天，奈爾說不能就這樣放棄，鬧了好久呢。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그래서 미나 씨가 3종 침식체를 잡아오면 인정해주겠다고 했잖아요.","JPN":"それで、ミナさんが第3種侵食体を捕まえてきたら認めると言われたまして。","ENG":"So you told her she'd pass if she could take down a Category 3 C.O.","TWN":"所以你說只要她能逮到3類侵蝕體，你就會認可她。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 나이엘 씨는 실패한 모양이지만…….","JPN":"どうやらナイエルさんは失敗したようでしたけど……","ENG":"But it seems Naielle wasn't able to do it...","TWN":"看來奈爾是失敗了……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"불합격이야. 이제 돌아가.","JPN":"不合格。もう帰って。","ENG":"You didn't pass. Go home.","TWN":"淘汰，你回去吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"에엣?! 아직 준비해 온 춤도 노래도 요리도 제대로 못 보여드렸는데요!","JPN":"ええっ！？　まだ準備してきたダンスも、歌も、料理もちゃんとお見せできていません！","ENG":"What?! But I still haven't shown you my dance moves, my singing skills, or my cooking!","TWN":"這麼快！？我有準備要唱歌、跳舞跟做菜欸！都還沒表演呢！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그런 걸 왜 준비해 온 거야…?","JPN":"なんでそんなの準備してきたの……？","ENG":"Why did you even prepare all of that...?","TWN":"準備這種東西要幹嘛…？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이미 결정난 일이야. 부모님 있는 데로 돌아가.","JPN":"もう決まったことだよ。ご両親のいるところに帰りな。","ENG":"The decision's been made. Go back to your family.","TWN":"事已成定局，你回去找你爸媽吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하아. 포기할 줄 모르네.","JPN":"はあ。諦めが悪いんだね。  ","ENG":"*Sigh* She's not going to give up, is she?","TWN":"哀，有夠堅持的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 어디 3종 침식체라도 잡아 와.","JPN":"じゃあ、どこかで第3種侵食体でも捕まえてきて。","ENG":"Then go defeat a Category 3 C.O.","TWN":"那你抓個3類侵蝕體來看看。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"3종 침식체를요?","JPN":"第3種侵食体をですか？","ENG":"A Category 3 C.O.?","TWN":"3類侵蝕體嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그래. 어차피 살면서 한 번 마주치기도 힘들겠지만.","JPN":"そう。どうせ一生に一度出くわすかどうかだろうけど。","ENG":"Yes. Even coming across one will be a once-in-a-lifetime experience.","TWN":"沒錯，不過3類侵蝕體也不是你想遇就遇得到的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"말도… 안 돼…….","JPN":"うそ……","ENG":"No... that can't be...","TWN":"不可能……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼, 정말로… 지원자가 노엘이 아니라, 나이엘로 바뀌었다는 거야……?","JPN":"じゃ、本当に……志願者がノエルじゃなくてナイエルだったことになってる……？","ENG":"So you're saying... the applicant really changed from Noelle to Naielle...?","TWN":"那麼，真的……面試的人從洛艾兒變成了奈爾……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그렇다면, 노엘은 대체……?","JPN":"だったら、ノエルはいったい……？","ENG":"Then what happened to Noelle...?","TWN":"那麼，洛艾兒到底……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"subtitle","speaker":null,"text":{"KOREA":"몇 시간 뒤","JPN":"数時間後","ENG":"A few hours later","TWN":"幾小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>\\n이스트 시티, 코핀 컴퍼니 샤레이드 지부.","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>\\nイーストシティ、コフィンカンパニーシャレード支部","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color>\\nEast City, Coffin Company Charade Branch.","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>\\n東城，科芬公司查雷德分部。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"어라, 미나야? 무슨 일이야?","JPN":"あれ、ミナ？　どうしたの？","ENG":"Oh? Mina! What's up?","TWN":"咦，米娜？怎麼了？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"여기 사무실은 내가 잘 관리하고 있어. 사장님께서도 잘 지내시지?","JPN":"こっちの事務所は私がちゃんと見ているよ。社長はお元気？","ENG":"I've been keeping things in order here at the office. Boss is doing well too, right?","TWN":"我把這裡的辦公室管理得很好，老闆你也過得不錯吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"스키너, 혹시 거기에 펠리세트랑 라이카 있어?","JPN":"スキナー、そこにフェリセットとライカはいる？","ENG":"Skinner, are Félicette and Laika there by any chance?","TWN":"史金納，費莉塞特和萊卡在那邊嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"중요한 일이 있는데, 두 사람 다 연락을 받지 않아서.","JPN":"大事な話があるんだけど、2人とも繋がらなくって。","ENG":"It's something important, but I haven't been able to reach either of them.","TWN":"有重要的事情，但兩個人都沒有接到聯絡。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"어라? 그러고 보니 이상하네?","JPN":"うん？　そういえばおかしいな。","ENG":"Huh... now that you mention it, that is odd.","TWN":"咦？這麼說來有點奇怪啊？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"원래 지금쯤이면 스케줄 마치고 돌아올 시간이거든.","JPN":"いつもならスケジュールを終えて帰ってくる頃なんだけど。","ENG":"They should've wrapped up their schedule and been back by now.","TWN":"原本現在這個時候應該是結束行程回來的時間了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아, 그래……?","JPN":"あ、そう……？","ENG":"Oh, is that so...?","TWN":"是嗎……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하하, 얘들이 요즘 워낙 바빠서 말이야.","JPN":"はは、あの子たちも最近忙しくてね。","ENG":"Haha, well, they've been super busy lately.","TWN":"哈哈，她們最近實在是太忙了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"슬슬 다음 시즌 대비도 해야 하고, 스폰서들이 많아지면서 광고 촬영도 많이 잡혔거든.","JPN":"そろそろ来シーズンにも備えないとだし、スポンサーが増えて広告撮影の予定も結構入ってるのよ。","ENG":"With the next season coming up and more sponsors on board, they've got a ton of ad shoots lined up.","TWN":"差不多該準備下個賽季了，贊助商越來越多，廣告拍攝也排得滿滿的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"뭐, 건틀렛 리그 챔피언이자, 세계를 구한 유명 인사들이니까 이 정도는 당연하려나?","JPN":"まあ、ガントレットリーグチャンピオンで、世界を救った有名人だし、これぐらい当然なのかな？","ENG":"I mean, they are Gauntlet League champions and world-saving celebrities. It's kind of expected, right?","TWN":"嗯，作為聖鎧聯賽冠軍和拯救世界的名人，這點待遇是理所當然的吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"미나, 너도 같이 있었으면 참 좋았을 텐데…….","JPN":"ミナも一緒ならよかったのに……","ENG":"It's just... it would've been nice if you were with them too, Mina...","TWN":"米娜，要是你也在就好了……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"음? 내가……?","JPN":"うん？　私……？","ENG":"Hmm? Me...?","TWN":"嗯？我……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아, 아하하…! 아무것도 아니야…!","JPN":"あ、あはは……！　なんでもない！","ENG":"A-ahaha...! It's nothing, really...!","TWN":"啊，啊哈哈…！沒什麼…！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"미나도 미나만의 사정이 있을 테니까……!","JPN":"ミナにはミナの事情があるだろうから……！","ENG":"I'm sure you've got your own stuff going on too, Mina...!","TWN":"米娜也有米娜的難處……！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아무튼 두 사람, 돌아오면 연락하라고 전할게.","JPN":"とにかく、2人が戻ってきたら連絡するように言っておくね。","ENG":"Anyway, I'll let them know to contact you when they're back.","TWN":"總之，兩個人回來後我會通知你。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응, 고마워.","JPN":"うん、ありがとう。","ENG":"Yeah, thanks.","TWN":"嗯，謝謝。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아, 맞아! 그러고 보니 네 액션 피규어는 어떻게 할래?","JPN":"そうだ！　そういえば、ミナのアクションフィギュアはどうする？","ENG":"Oh, right! Speaking of which, what do you want to do with your action figure?","TWN":"啊，沒錯！對了，你的公仔打算怎麼辦？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"우리 사무실에 견본이 도착했거든. 지금 로터스 지부에 머물고 있지? 그리로 부쳐줄까?","JPN":"事務所に見本が届いたの。今ロータス支部にいるよね？　そっちに送ろうか？","ENG":"The sample arrived at our office. You're staying at the Lotus Branch, right? Should I send it over?","TWN":"我們辦公室收到了樣品。你現在在洛德斯分部嗎？要寄到那裡嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"내 액션 피규어라고? 그게 뭔데?","JPN":"私のアクションフィギュア？　何それ？","ENG":"My action figure? What are you talking about?","TWN":"我的公仔？那是什麼？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"미나도 참~ 그새 잊어버린 거야?","JPN":"ミナったら、もう忘れちゃったの？","ENG":"Come on, Mina. Did you really forget already?","TWN":"米娜真是的～這麼快就忘了嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"리그에서 우승하면 우승자를 본뜬 액션 피규어가 나온다고 했잖아.","JPN":"リーグで優勝したら、優勝者の姿を模ったアクションフィギュアが作られるって言ったじゃない。","ENG":"They said a custom action figure gets made, modeled after the Gauntlet winner, remember?","TWN":"不是說在聯賽中獲勝的話會出一個以冠軍為原型的公仔嗎。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"원래부터 한정 상품인 데다가, 오랜만에 챔피언이 교체돼서 엄청 프리미엄이 붙었거든.","JPN":"元々限定賞品だし、チャンピオン交代は久しぶりだからすごくプレミアがついてるんだ。","ENG":"It's a limited edition, and since it's been a while since the champion changed, it's gotten super valuable.","TWN":"本來就是限量商品，加上很久才更換一次冠軍，所以非常有價值。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"건틀렛은 은퇴했어도, 하나쯤은 기념 삼아 가지고 있는 게 어때?","JPN":"ガントレットは引退したけど、記念に1個ぐらい持ってたらどう？","ENG":"Even if you've retired from the Gauntlet, wouldn't it be nice to keep one as a memento?","TWN":"聖鎧雖然退役了，但留一個作為紀念怎麼樣？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"잠깐……?","JPN":"ちょっと……","ENG":"Wait, what...?","TWN":"等一下……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"지금… 무슨 소리야? 내가 건틀렛을 은퇴하다니……?","JPN":"それって……何の話？　私がガントレットを引退する……？","ENG":"What do you mean I retired from the Gauntlet...?","TWN":"現在……是什麼聲音？我退出聖鎧……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나는 애초에 리그에 참가한 적도 없는데……?","JPN":"そもそも私はリーグに参加したことすらないのに……？","ENG":"I've never even competed in the league to begin with...","TWN":"我根本就沒有參加過聯賽……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"……미나야.","JPN":"……ミナ。","ENG":"...Mina.","TWN":"……米娜啊……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"너한테 어떤 사정이 있었는지는 잘 모르겠지만…….","JPN":"どういう事情があったのかはわからないけど……","ENG":"I don't know what happened on your end...","TWN":"雖然不知道你發生了什麼事……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그래도 우리가 한 팀이었다는 걸 부정하는 건 조금 슬프다고 할까, 하하…….","JPN":"それでも、私たちが1つのチームだったことを否定されると、少し悲しいというか……はは……","ENG":"But it's kind of sad to hear you deny that we were ever a team, haha...","TWN":"不過否認我們曾經是一個團隊，這種話有點傷感啊，哈哈……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐, 뭐라고……?","JPN":"な、なに……？","ENG":"W-what...?","TWN":"什，什麼……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"정말 기억 안 나?","JPN":"本当に覚えていないの？","ENG":"You really don't remember?","TWN":"真的不記得了嗎？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"너희 세 사람이 힘을 합해, 전대 챔피언 오지만디아스를 쓰러트렸잖아.","JPN":"ミナたち3人が力を合わせて、先代のチャンピオンであるオジマンディアスを倒したじゃない。","ENG":"The three of you teamed up and defeated the former champion, Ozymandias.","TWN":"你們三個人合力打敗了前任冠軍奧茲曼迪亞斯。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"마지막 승부에서 네가 오지만디아스를 막아주지 않았다면 아마도 우리는 졌을 거야.","JPN":"最後の勝負でミナがオジマンディアスを止めてくれなかったら、多分私たちは負けてたよ。","ENG":"If you hadn't held off Ozymandias in that final match, we probably would've lost.","TWN":"如果在最後的決戰中你沒有阻止奧茲曼迪亞斯，我們可能就輸了。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"펠리세트, 라이카 두 사람이라도 관리국 공인 S급 카운터를 당해낼 수는 없었을 테니까.","JPN":"いくらフェリセットとライカでも、管理局公認のS級カウンターには敵わないし。","ENG":"Even Félicette and Laika couldn't have handled an Administration confirmed Grade S Counter.","TWN":"即使是費莉塞特和萊卡兩個人，也無法對抗管理局公認的S級制裁者。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그래서 네가 리그 시상식에서 돌연 은퇴 선언을 했을 때, 다들 얼마나 놀랐는데…….","JPN":"だからあなたがリーグの授賞式で突然引退宣言をしたとき、みんなびっくりしたんだから。","ENG":"That's why when you suddenly announced your retirement during the award ceremony, everyone was stunned...","TWN":"所以當你在聯賽頒獎典禮上突然宣佈退役時，大家都驚呆了……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"우승 당일에 팀 해체라니… 리그 역사 상, 전대미문의 사태였다고…….","JPN":"なにせ優勝当日にチーム解散なんて……リーグ史上前代未聞の事件だったからね。","ENG":"Disbanding the team on the very day you won... It was an unprecedented moment in Gauntlet League history!","TWN":"在奪冠當天解散球隊……這是聯賽歷史上前所未有的事態……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"내, 내가 그랬다고……?","JPN":"わ、私がそんなことを……？","ENG":"I-I really did that...?","TWN":"我，我做了……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"멤버 불화설, 지분 문제, 등등……. 뭐, 여러 추측성 루머가 나돌긴 했지.","JPN":"メンバーの不仲説、取り分をめぐる問題だとか……いろんな憶測が出回ったわ。","ENG":"Rumors flew around... including infighting between members, disputes over shares, and all kinds of speculation.","TWN":"成員不和的傳聞、股份問題等等……嗯，各種猜測性的傳聞確實很多。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"물론, 다음날 시니어가 살해되고, 최고등급 재난경보가 떨어지면서 묻혀버렸지만…….","JPN":"もちろん、次の日にシニアが殺害されて、最高ランクの災難警報まで出たせいで、有耶無耶になったけど……","ENG":"But they were quickly forgotten the next day, after the Senior was killed and a highest-level disaster alert was declared...","TWN":"當然，第二天高級員工被殺，最高級別的災難警報響起，一切都被掩蓋了……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아하하! 승리의 브이, 브이!","JPN":"あはは！　勝利のピース、ピース！","ENG":"Ah hah hah! V for victory! V!","TWN":"哈哈哈！勝利的V！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"해냈어요, 펠리세트! 정말 우승했다구요!","JPN":"やりましたよ、フェリセット！　本当に優勝しちゃったんですよ！","ENG":"We did it, Félicette! We really won!","TWN":"我們做到了，費莉塞特！我們真的奪冠了！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"모두 힘을 합쳐서 꿈을 이루어서 너무 기뻐요!","JPN":"みんなで力を合わせて夢を叶えられて、本当に嬉しいです！","ENG":"I'm so happy that everyone got together and achieved this dream!","TWN":"大家同心協力實現夢想，我真的好開心！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"리그에서 우승해서 펜릴 소대의 이름을 드높였으니, 펜릴 소대 동상이 세워지겠죠?","JPN":"リーグで優勝したことでフェンリル小隊の名もあげられましたし、フェンリル小隊の銅像も建てられるでしょうね？","ENG":"Since we won, the reputation of Fenrir Squad must have gone up. Do you think they'll put up a Fenrir Squad statue?","TWN":"聯賽中奪冠後，芬里爾小隊知名度也因此大大提升，那應該會建一個芬里爾小隊的銅像吧？"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 영광을 소대장님과 선배님들께 바칩니다아!!","JPN":"この栄光を、小隊長と先輩方に捧げますぅ！！","ENG":"I dedicate this honor to our commander and my fellow Fenrir Squad members!!","TWN":"我要把這份榮耀獻給小隊長和前輩們！！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하하, 동상까지는 몰라도 우릴 본딴 액션 피규어는 나올 거예요.","JPN":"銅像が建つかどうかはわかりませんが、私たちのフィギュアぐらいなら作られると思いますよ。","ENG":"Haha, I don't know about a statue, but they will make action figures of us.","TWN":"哈哈，建不建銅像不確定，但應該會出我們的周邊公仔。"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오오! 정말요?! ","JPN":"おお！　本当ですか！？","ENG":"Ooh! Really?!","TWN":"哇喔！真的嗎？！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 쪼잔하게 액션 피규어가 다 뭐냐?","JPN":"おい、アクションフィギュアだなんてスケールが小さいだろ。","ENG":"Why are you so excited about some action figures like a cheapskate?","TWN":"喂，你們這些沒見過世面的傢伙，公仔算什麼？"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"리그 상금만으로도 몇 년은 일 안하고 먹고 살 수 있을 걸?","JPN":"リーグの賞金だけでも数年は働かなくても生きていける金額だぞ？","ENG":"With the league's prize money, we can live a comfortable life for a few years without having to work!","TWN":"光是聯賽獎金就足以讓我們不用工作好幾年吧？"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"궁상맞게 이런 데서 상금 얘기 하지 마요! 아무렴 어때요!","JPN":"こんなときに賞金だの下世話なこと言わないでよ！　そんなのどうだっていいでしょ！","ENG":"Will you please stop talking about money right now?! Who cares?!","TWN":"別談獎金這種世俗的東西！獎金才不重要！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"지금은…… 기뻐하기에도 바쁘니까!","JPN":"今は……喜ぶだけで精一杯なんだから！","ENG":"Because right now... I'm too busy being happy!","TWN":"重要的是……現在開心都來不及啦！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"미나야? 듣고 있어?","JPN":"ミナ？　聞いてる？","ENG":"Mina? Are you listening?","TWN":"米娜？你在聽嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"미안… 널 탓하려던 건 아니었는데…….","JPN":"ごめん……責めるつもりはなかったんだけど……","ENG":"Sorry... I didn't mean to make it sound like it was your fault...","TWN":"抱歉……我不是想責怪你……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아니야. 나야말로 갑자기 연락해서 미안해.","JPN":"いや、私こそ突然連絡してごめん。","ENG":"No, I'm the one who should apologize for calling so suddenly.","TWN":"不，突然聯絡你的是我，對不起。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"잠시 일이 생겨서 끊어야겠어. 나중에 다시 연락할게.","JPN":"ちょっと用事ができて一旦切るね。あとでまた連絡する。","ENG":"Something's come up. I'll contact you later.","TWN":"我有點事要處理，得掛電話了，我以後再聯絡你。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"웃기지 마…….","JPN":"ふざけないで……","ENG":"This is ridiculous...","TWN":"別開玩笑了……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"다들 웃기지 말라고……!!","JPN":"みんな、ふざけないでよ……！！","ENG":"You've all got to be kidding me...!","TWN":"大家別開玩笑了……！！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"모두가 그 녀석을 잊어버린 것도 모자라서…….","JPN":"みんながあいつのことを忘れて……","ENG":"First, everyone forgets her like she never existed...","TWN":"所有人不僅忘記了那傢伙……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이번에는 내가 리그 우승자라고…!? 그럼 내가 노엘의 승리를 빼앗았다는 거야……!?","JPN":"今度は、私がリーグ優勝者……！？　じゃあ、私がノエルの勝利を奪ったってこと……！？","ENG":"And now you're telling me I'm the Gauntlet winner...? Are you saying... I stole Noelle's victory?","TWN":"這次我是聯賽冠軍……？！那就是說我奪走了洛艾兒的勝利……？！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"웃기지 마! 뭐가 어떻게 돌아가는 건데?","JPN":"ふざけないでよ！　いったい何がどうなってるんだ？","ENG":"Don't mess with me! What is going on here?!","TWN":"別開玩笑了！到底是怎麼回事？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘이 사라진 뒤로, 모든 게 뒤죽박죽이잖아……!","JPN":"ノエルが消えてからすべてがめちゃくちゃじゃん……！","ENG":"Ever since Noelle disappeared, everything's been a mess...!","TWN":"洛艾兒消失後，一切都亂套了……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"제길……!","JPN":"くそ……！","ENG":"Damn it...!","TWN":"可惡……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭔가 안 좋은 느낌이 들어……!","JPN":"なんだか、嫌な予感がする……！","ENG":"Something feels seriously wrong...!","TWN":"感覺有些不妙……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"대체 노엘은 어디 있는 거야……?","JPN":"いったいノエルはどこにいるの……？","ENG":"Where is Noelle...?!","TWN":"洛艾兒到底在哪裡……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"대체 어째서… 이런 일이 일어나는 거냐고……!","JPN":"なんで……こんなことになっちゃったのよ……！","ENG":"Why is all of this happening...?!","TWN":"到底為什麼……會發生這種事啊……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"카나리아 스쿼드의 행방을 놓친 건 아쉽게 됐지만…….","JPN":"カナリア・スクワッドの行方が抜けていたことは残念だけど……","ENG":"Losing track of the Canary Squad is a setback, but still...","TWN":"雖然很遺憾沒能找到金絲雀小隊的下落……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都在劇本之中。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"짐작한 대로, 유미나만큼은 노엘 라이트를 기억하고 있군.","JPN":"予想したとおり、ヤナギ・ミナだけはノエル・ライトを覚えている。","ENG":"As expected, Yoo Mina is the only one who remembers Noelle Wright.","TWN":"果然，只有劉米娜記得洛艾兒·萊特。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면…….","JPN":"だとしたら……","ENG":"In that case...","TWN":"那麼……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시 이 각본의 주인공은 당신이 되겠군요.","JPN":"やはり、この脚本の主人公はあなたになりますね。","ENG":"It seems you were meant to be the protagonist of this script after all.","TWN":"果然，這個劇本的主角將會是你。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……늑대. 유미나.","JPN":"……オオカミ、ヤナギ・ミナ。","ENG":"…The Wolf. Yoo Mina.","TWN":"……狼，劉米娜。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"subtitle","speaker":null,"text":{"KOREA":"몇 시간 뒤","JPN":"数時間後","ENG":"A few hours later","TWN":"幾小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>로터스</color>\\n아마니 밸리, 코핀 컴퍼니 임시 지부","JPN":"管理局直轄都市<color=#ffd34c>ロータス</color>\\nアマニーバレー、コフィンカンパニーの臨時支部","ENG":"Administration Direct Control City, <color=#ffd34c>Lotus</color>\\nAmani Valley, Temporary Coffin Company Branch","TWN":"管理局直轄城市<color=#ffd34c>洛德斯</color>\\n阿瑪尼山谷，科芬公司臨時支部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"불렀어, 부사장님?","JPN":"副社長、呼んだ？","ENG":"You called, Vice President?","TWN":"你叫我嗎，副總？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이렇게 늦은 시간에 미안하군요, 미나 양.","JPN":"遅い時間にすみませんね、ミナさん。","ENG":"Sorry to bother you at such a late hour, Mina.","TWN":"這麼晚了，真是抱歉，米娜。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"괜찮아, 어차피 잠도 안 오던 참이었거든.","JPN":"いいよ、どうせ眠れなかったし。","ENG":"It's fine. I couldn't sleep anyway.","TWN":"沒關係，反正我也睡不著。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 노엘 라이트라는 아이 때문인가요?","JPN":"ノエル・ライトという子の件でですか？","ENG":"Is it because of that girl, Noelle Wright?","TWN":"是因為那個叫洛艾兒·萊特的孩子嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……부사장님 말이 맞았어.","JPN":"……副社長の言った通りだったよ。","ENG":"...You were right.","TWN":"……副總的話沒錯。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하루 종일 노엘에 관해서 묻고 다녔는데, 아무도 노엘을 기억하지 못하더라고.","JPN":"一日中ノエルについて聞いて回ったけど、誰もノエルのことを覚えていなかった。","ENG":"I spent the whole day asking around about Noelle, but no one remembered her.","TWN":"我整天都在打聽洛艾兒的事，但沒有人記得洛艾兒。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"마치, 이 세계에서 노엘이라는 녀석만 쏙 빠져버린 것처럼 말이야.","JPN":"まるでこの世界から、ノエルという人だけが抜け落ちたかのようにね。","ENG":"As if she's been plucked out of existence.","TWN":"就好像，這個世界上只有洛艾兒這個傢伙消失了一樣。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 뿐만이 아니야.","JPN":"それだけじゃない。","ENG":"And that's not all.","TWN":"不只如此。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"펜릴 소대에 신규 입사 지원을 했던 사람은 나이엘이 되어 있었고…….","JPN":"フェンリル小隊に志願したのはナイエルになっていたし……","ENG":"The one who applied to the Fenrir Squad... was listed as Naielle...","TWN":"申請加入芬里爾小隊的人變成了奈爾……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"펠리세트랑 라이카와 함께 건를렛 리그를 우승했던 건, 내가 되어 있었어…….","JPN":"フェリセットやライカと共にガントレットリーグで優勝したのは、私ってことになっていた……","ENG":"The one who won the Gauntlet League alongside Félicette and Laika... was apparently me.","TWN":"和費莉塞特、萊卡一起贏得聖鎧聯賽的那個人，原來是我……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"과거가 뒤죽박죽 엉켜버렸는데, 다들 너무 태연하니까 오히려 내 기억을 의심하게 되더라?","JPN":"過去が全部めちゃくちゃなのに、みんな平然としすぎてて、逆に自分の記憶を疑っちゃったよ。","ENG":"The past has been twisted into something unrecognizable, and everyone's acting so normal. So I started questioning my own memories.","TWN":"過去的事情變得一團糟，但大家都太鎮定了，反而讓我開始懷疑自己的記憶了？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"정말로 노엘이라는 녀석이 있었던가…? 하고서 말이지.","JPN":"本当にノエルって存在してたっけ……ってね。","ENG":"Was there ever really someone named Noelle...? I actually started to wonder.","TWN":"真的有個叫洛艾兒的傢伙嗎…？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그렇지만…….","JPN":"でも……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 우선 자기 소개부터 해 봐.","JPN":"じゃあ、まず自己紹介からして。","ENG":"Then, could you first introduce yourself?","TWN":"那你先自我介紹吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"노엘 라이트입니다! 취미는 노래방에서 노래 부르기고, 특기는 요리예요!","JPN":"ノエル・ライトです！　趣味はカラオケで歌うことで、料理が得意です！","ENG":"I'm Noelle Wright! I like to go singing in karaoke! Also, cooking is my specialty!","TWN":"我叫洛艾兒·萊特！興趣是去KTV唱歌，專長是做菜！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"요리?","JPN":"料理？","ENG":"Cooking?","TWN":"做菜？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네. 넷튜브에 영상도 올리고 있어요. 조회수는 낮지만요, 헤헤.","JPN":"はい。ネットチューブに動画もアップしてるんです。再生数は少ないですけど、へへ。","ENG":"Yup! I even upload them on NetTube. But I don't get that many views, he he.","TWN":"是，我還有把做菜的影片PO上網，但瀏覽次數不多，哈哈。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…부모님은?","JPN":"……ご両親は？","ENG":"...What about your parents?","TWN":"…那你爸媽呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"두 분 모두 잘 지내고 계세요.","JPN":"2人とも健在です。","ENG":"Both are alive and well.","TWN":"他們還在世，"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"같이 농사를 하시면서 커다란 골든 리트리버도 키우세요.","JPN":"農業をやりながら、大きなゴールデンレトリーバーも飼ってます。","ENG":"They own a farm and raise a massive golden retriever.","TWN":"現在一起種田，還有養一隻黃金獵犬。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이름은 치즈예요. 털이 무척 노랗거든요.","JPN":"名前はチーズっていいます。毛がチーズみたいに黄色いので。","ENG":"His name is Cheese! Because his fur is really yellow.","TWN":"牠叫起司，毛很黃。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 부모님이랑 같이 농사나 짓지, 왜 용병이 되려는 거야?","JPN":"じゃあ、ご両親と一緒に農業をすればいいのに、なんで傭兵になろうとするの？","ENG":"Then shouldn't you be helping your parents out with their farm? Why do you want to be a mercenary?","TWN":"那你為什麼不和他們一起種田，來當什麼傭兵？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펜릴 소대가 너무 좋아서요!","JPN":"フェンリル小隊が大好きなので！","ENG":"Because I like Fenrir Squad a lot!","TWN":"因為我太愛芬里爾小隊了！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"영상을 보고 푹 빠졌어요. 특히 유미나 님이 정말 정말 멋졌거든요.","JPN":"動画を見てハマりました。特にミナ様が本当に本当～にカッコよかったんです。","ENG":"I fell in love with them after watching the video. I thought you were especially cool, Ms. Mina.","TWN":"我看到影片後整個愛了！尤其是劉米娜小姐真的超帥的！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"유미나 님은 제 우상이에요! 물론 힐데 소대장님도! 주시윤 님도!","JPN":"ミナ様は私のアイドルです！　もちろんヒルデ小隊長様も！　シリュウ様も！","ENG":"You're like my role model! Of course, I consider Commander Hilde and Mr. Joo Shiyoon to be role models as well!","TWN":"劉米娜小姐是我的偶像！當然希爾德小隊長也是！周時雲先生也是！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아이 러브 펜릴!","JPN":"アイ・ラブ・フェンリル！","ENG":"I love Fenrir!","TWN":"我愛芬里爾！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L28_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그렇지만, 나는 틀림없이 노엘을 기억하고 있어.","JPN":"でも、私は確かにノエルを覚えてる。","ENG":"But I remember Noelle clearly.","TWN":"不過，我肯定記得洛艾兒。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그러니까… 누가 뭐래도 나는 나 스스로를 믿고, 그 녀석을 찾아내겠어……!","JPN":"だから……誰になんと言われようと、私は自分を信じてあいつを見つけ出す……！","ENG":"So no matter what anyone says, I'll trust myself and I'll find her...!","TWN":"所以……無論別人怎麼說，我都相信自己，一定會找到那傢伙……！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"분명, 노엘도 그런 나를 믿고 기다리고 있을 테니까.","JPN":"きっとノエルも、そんな私を信じて待っているはずだから。","ENG":"Because I'm sure Noelle's out there, trusting me and waiting for me.","TWN":"因為洛艾兒也一定會相信我，等著我的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확실히. 이제 제법 선배티가 나는군요.","JPN":"確かに、先輩という感じですね。","ENG":"You're starting to sound like someone to look up to now.","TWN":"確實，現在已經有前輩的樣子了。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쩌면 미나 양에게 후배가 있다는 말이 정말일지도 모른다는 느낌이 드네요.","JPN":"もしかしたらミナさんに後輩がいるという話は本当かもしれませんね。","ENG":"I'm beginning to believe it might really be true that someone actually calls you their mentor.","TWN":"說不定米娜真的有後輩了呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐? 그럼……?","JPN":"え？　じゃあ……","ENG":"Wait, what do you mean...?","TWN":"什麼？那……？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"실은, 사장님의 지시로 미나 양이 말했던 노엘 라이트 양에 관해 조사해 보았답니다.","JPN":"実は社長の指示で、ミナさんが言っていたノエル・ライトさんのことを調べてみたんです。","ENG":"Well... under Boss's orders, I did a little digging into this Noelle Wright you've been talking about.","TWN":"其實，我按照老闆的指示調查了米娜提到的洛艾兒·萊特。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 꽤나 뜻밖의 결과를 얻게 되었어요.","JPN":"そして意外な結果が得られました。","ENG":"And the results... were quite unexpected.","TWN":"而且還得到了意想不到的結果。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뜻밖의 결과라고?","JPN":"意外な結果？","ENG":"Unexpected?","TWN":"意外的結果嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미리 말씀드리자면, 이건 미나 양이 기대하고 있는 정보가 아닐 겁니다.","JPN":"言っておきますが、これはミナさんが期待している情報とは違うでしょう。","ENG":"I should warn you, this probably isn't the information you were hoping for, Mina.","TWN":"提前告訴你，這不是米娜期待的資訊。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 늘 그렇듯, 모든 문제의 해결은 그것을 똑바로 직시하는 것으로부터 시작되죠.","JPN":"ですが、問題解決はそれと向き合わずしては始まらないものです。","ENG":"But as always, solving any problem begins with facing the truth head-on.","TWN":"但一如既往，解決所有問題都是從正視問問題開始的。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 잘 들으세요, 미나 양.","JPN":"だからよく聞いてください、ミナさん。","ENG":"So listen carefully, Mina.","TWN":"所以請仔細聽，米娜。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"노엘 라이트.","JPN":"ノエル・ライト。","ENG":"Noelle Wright.","TWN":"洛艾兒·萊特。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그녀는 이미 20년 전 대정화 전쟁에서 사망했습니다.","JPN":"彼女は20年前の大浄化戦争で死亡しました。","ENG":"She died during the Grand Purification War, twenty years ago.","TWN":"她已經在20年前的大淨化戰爭中去世了。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"고철 더미가 떠 있는 샤레이드와 로터스의 관리 경계 구역, 바로 그 땅에서 말이죠.","JPN":"鉄くずの浮くシャレードとロータスの管理警戒区域で。","ENG":"In the Charade-Lotus perimeter zone, right where Scraps is floating.","TWN":"在漂浮著廢鐵堆的查雷德和洛德斯的管理邊界區域，就是那片土地上。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐……?","JPN":"え……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"무슨 소리야? 노엘이 죽은 사람이라고?","JPN":"どういうこと？　ノエルがすでに死んでいる？","ENG":"What are you talking about? Noelle is dead?","TWN":"什麼意思？洛艾兒是死人？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 미나 양…….","JPN":"そして、ミナさん……","ENG":"And Mina...","TWN":"還有米娜……"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신은 지금 <color=#ffd34c>정보 말소</color>의 후유증을 겪는 거예요.","JPN":"あなたは今、<color=#ffd34c>情報抹消</color>の後遺症を患っています。","ENG":"You're experiencing the aftereffects of <color=#ffd34c>information erasure</color>.","TWN":"你現在正在經歷<color=#ffd34c>資訊抹消</color>的後遺症。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"정보… 말소라고……?","JPN":"情報……抹消……？","ENG":"Information... erasure...?","TWN":"資訊……被抹消了……？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_LOGIN2","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};